+    // =========================================================================
+    // Dynamic Top-1 - Skip cold experts for instant response
+    // =========================================================================
+
+    /// Enable/disable turbo mode (Dynamic Top-1)
+    pub fn setTurboMode(self: *Self, enabled: bool) void {
+        self.turbo_mode = enabled;
+        if (enabled) {
+            log.info("⚡ Turbo Mode ENABLED: Will skip cold experts when hot expert available", .{});
+        } else {
+            log.info("🐢 Turbo Mode DISABLED: Full Top-2 expert computation always", .{});
+        }
+    }
+
+    /// Check if we should skip Expert B (Top-2) to avoid SSD wait
+    /// Returns true if: turbo_mode enabled AND Expert A is hot AND Expert B is cold
+    pub fn shouldSkipColdExpert(self: *Self, expert_a: u32, expert_b: u32) bool {
+        if (!self.turbo_mode) return false;
+
+        const a_is_hot = self.isExpertPinned(@intCast(expert_a)) or
+            self.getPrefetchedBuffers(expert_a) != null;
+        const b_is_hot = self.isExpertPinned(@intCast(expert_b)) or
+            self.getPrefetchedBuffers(expert_b) != null;
+
+        // Skip B only if A is instant but B requires SSD
+        if (a_is_hot and !b_is_hot) {
+            self.top1_fallbacks += 1;
+            return true;
+        }
+
+        self.top1_full_computes += 1;
+        return false;
+    }
+
+    /// Get Dynamic Top-1 statistics
+    pub fn getTurboStats(self: *Self) struct {
+        fallbacks: u64,
+        full_computes: u64,
+        fallback_rate: f32,
+    } {
+        const total = self.top1_fallbacks + self.top1_full_computes;
+        const fallback_rate = if (total > 0)
+            @as(f32, @floatFromInt(self.top1_fallbacks)) / @as(f32, @floatFromInt(total))
+        else
+            0.0;
+        return .{
+            .fallbacks = self.top1_fallbacks,
+            .full_computes = self.top1_full_computes,
+            .fallback_rate = fallback_rate,
+        };
+    }
+
+    /// Log turbo mode statistics
+    pub fn logTurboStats(self: *Self) void {
+        const stats = self.getTurboStats();
+        if (stats.fallbacks + stats.full_computes > 0) {
+            log.info("⚡ Dynamic Top-1: {d} fallbacks, {d} full computes, {d:.1}% turbo rate", .{
+                stats.fallbacks,
+                stats.full_computes,
+                stats.fallback_rate * 100.0,
+            });
+            if (stats.fallback_rate > 0.3) {
+                log.info("   ✅ Turbo Mode effective! {d:.0}% of tokens avoided SSD wait.", .{
+                    stats.fallback_rate * 100.0,
+                });
+            }
+        }
+    }
+
